from __future__ import annotations
from dataclasses import dataclass
from typing import Dict, List, Tuple


@dataclass
class HexRecord:
    byte_count: int
    address: int
    record_type: int
    data: bytes
    checksum: int


class IntelHexError(ValueError):
    pass


class IntelHexImage:
    def __init__(self) -> None:
        self.memory: Dict[int, int] = {}
        self.start_linear_address: int | None = None

    @property
    def min_address(self) -> int | None:
        return min(self.memory.keys()) if self.memory else None

    @property
    def max_address(self) -> int | None:
        return max(self.memory.keys()) if self.memory else None

    def row_addresses(self, row_size: int = 16) -> List[int]:
        rows = {addr - (addr % row_size) for addr in self.memory.keys()}
        return sorted(rows)

    def row_bytes(self, row_base: int, row_size: int = 16) -> List[int | None]:
        return [self.memory.get(row_base + i) for i in range(row_size)]


def _parse_record(line: str, line_no: int) -> HexRecord:
    s = line.strip()
    if not s:
        raise IntelHexError(f"Line {line_no}: empty line")
    if not s.startswith(":"):
        raise IntelHexError(f"Line {line_no}: missing ':'")

    hexpart = s[1:]
    if len(hexpart) < 10 or len(hexpart) % 2 != 0:
        raise IntelHexError(f"Line {line_no}: invalid length")

    try:
        raw = bytes.fromhex(hexpart)
    except ValueError as e:
        raise IntelHexError(f"Line {line_no}: non-hex characters") from e

    byte_count = raw[0]
    if len(raw) != 5 + byte_count:
        raise IntelHexError(
            f"Line {line_no}: byte count mismatch (declared {byte_count}, actual {len(raw)-5})"
        )

    addr = (raw[1] << 8) | raw[2]
    rtype = raw[3]
    data = raw[4:4 + byte_count]
    checksum = raw[-1]

    # Intel HEX checksum: sum(all bytes including checksum) & 0xFF == 0
    if (sum(raw) & 0xFF) != 0:
        raise IntelHexError(f"Line {line_no}: checksum error")

    return HexRecord(byte_count, addr, rtype, data, checksum)


def parse_intel_hex(text: str) -> IntelHexImage:
    image = IntelHexImage()
    upper_addr = 0
    eof_seen = False

    for i, line in enumerate(text.splitlines(), start=1):
        if not line.strip():
            continue

        rec = _parse_record(line, i)

        if rec.record_type == 0x00:  # Data
            base = upper_addr + rec.address
            for ofs, b in enumerate(rec.data):
                image.memory[base + ofs] = b

        elif rec.record_type == 0x01:  # EOF
            eof_seen = True
            break

        elif rec.record_type == 0x02:  # Extended Segment Address
            if rec.byte_count != 2:
                raise IntelHexError(f"Line {i}: type 02 must have 2 bytes")
            seg = (rec.data[0] << 8) | rec.data[1]
            upper_addr = seg << 4

        elif rec.record_type == 0x04:  # Extended Linear Address
            if rec.byte_count != 2:
                raise IntelHexError(f"Line {i}: type 04 must have 2 bytes")
            upper = (rec.data[0] << 8) | rec.data[1]
            upper_addr = upper << 16

        elif rec.record_type == 0x05:  # Start Linear Address (optional)
            if rec.byte_count == 4:
                image.start_linear_address = int.from_bytes(rec.data, "big")

        else:
            # Other record types are ignored for viewer purposes
            pass

    if not eof_seen:
        raise IntelHexError("EOF record (type 01) not found")

    return image
